async (page) => {
  var title = "图解 Blaze · 第 20 章 · 扩展体系与框架自用机制 — 图解 Blaze-Persistence";
  var html = "<section style=\"margin-bottom:24px;\">\n<h2 style=\"font-size:24px;font-weight:800;color:#1a1a2e;line-height:1.4;margin:0 0 8px;\">第 20 章 · 扩展体系与框架自用机制</h2>\n</section>\n<section><p style=\"font-size:14px;color:#888;margin-bottom:28px;line-height:1.7;\">JpqlFunction · JpqlMacro · DbmsDialect · ObjectBuilder · EntityViewListener · ViewFilter · ConfigContributor · Spring Data</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff22;border-radius:10px;padding:20px 22px 14px;margin:0 0 28px;line-height:1.9;\"><p style=\"font-size:15px;color:#2b2b2b;margin-bottom:10px;line-height:1.8;\">Blaze-Persistence 不仅仅提供了一套强大的查询 API——它本身就构建在一套精心设计的扩展体系之上。框架核心功能——窗口函数、CTE、方言适配、Entity View 映射——全部通过同一套 SPI 实现。理解这些扩展点，既是理解框架内核的钥匙，也是打造业务定制能力的基石。</p><ul style=\"margin:8px 0 8px 20px;color:#2b2b2b;\"><li style=\"margin-bottom:4px;font-size:13px;\">查询扩展：JpqlFunction 自定义函数 · JpqlMacro 宏表达式 · DbmsDialect 方言适配</li><li style=\"margin-bottom:4px;font-size:13px;\">View 扩展：ObjectBuilder ResultSet 桥接 · EntityViewListener/ViewFilter 业务横切</li><li style=\"margin-bottom:4px;font-size:13px;\">集成与全景：Spring Data Repository 扩展 · 零配置自动注册 · 框架 Dogfooding 全景</li></ul><p style=\"font-size:12px;color:#888;margin-top:10px;padding-top:10px;border-top:1px solid #e5e7eb;\">前置知识：<span style=\"color:#1e6fff;\">第 14 章 · SQL 渲染</span> 的渲染管线概念，<span style=\"color:#1e6fff;\">第 15 章 · JPA Provider 适配</span> 的 Provider 抽象，以及 <span style=\"color:#1e6fff;\">第 19 章 · 代码到 SQL 全路径追踪</span> 的执行路径。</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">20.1 扩展点全景图</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">Blaze-Persistence 的扩展点分布在三个层次：<strong style=\"color:#1a1a2e;font-weight:700;\">Core Layer</strong>（查询构建与 SQL 渲染）、<strong style=\"color:#1a1a2e;font-weight:700;\">Entity View Layer</strong>（对象映射与生命周期）、<strong style=\"color:#1a1a2e;font-weight:700;\">Integration Layer</strong>（Spring / Quarkus 框架集成）。下图将所有 SPI 接口映射到查询生命周期的对应阶段。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 20-1 Blaze-Persistence 扩展点全景架构</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">CORE</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">JpqlFunction<br/>自定义函数渲染</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">JpqlMacro<br/>宏表达式展开</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">DbmsDialect<br/>数据库方言适配</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">ObjectBuilder<br/>结果映射构建</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">CriteriaBuilderConfiguration<br/>Contributor<br/>启动时自动配置</p></section></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">VIEW</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">EntityViewListener<br/>视图生命周期钩子</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">ViewFilter<br/>可复用命名过滤器</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">ViewFilterProvider<br/>过滤参数动态提供</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">EntityViewManager SPI<br/>视图管理器接口</p></section></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">INTEG</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">EntityViewSpecification<br/>Executor 动态查询</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">KeysetAwareRepository<br/>游标分页</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">EntityViewRepository<br/>视图仓库基类</p></section></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">表达式解析<br/>ExpressionParser</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">SQL 渲染<br/>SqlQueryGenerator</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">JDBC 执行</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">返回结果</p></section></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n\n\nSPI 接口所属层职责典型用户用例框架内部自用\n\n\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">JpqlFunction</code>Core注册自定义 JPQL 函数并渲染为原生 SQLarray_agg, 全文搜索, GIS 函数SET_UNION, WINDOW_ROW_NUMBER 等 30+ 函数\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">JpqlMacro</code>Core表达式解析前宏展开审计列注入, 租户 ID 宏VIEW_ROOT, EMBEDDING_VIEW_ROOT\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">DbmsDialect</code>Core数据库差异适配自定义方言覆盖PostgreSQL / MySQL / Oracle / H2 / DB2 / SQL Server\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">ObjectBuilder</code>CoreObject[] 元组 → 目标对象自定义 DTO 构建ViewTypeObjectBuilder 构建 Entity View 代理\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityViewListener</code>View视图创建/更新/删除生命周期钩子审计日志, 事件发布脏跟踪初始化, 级联传播, 版本校验\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">ViewFilter</code>View可复用命名过滤器软删除, 多租户, 状态过滤纯用户扩展点\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">ConfigurationContributor</code>CoreServiceLoader 自动注册配置自动注册函数/方言包Hibernate / EclipseLink Provider 注册\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityViewRepository</code>IntegrationSpring Data Entity View 仓库CRUD + 派生查询SimpleEntityViewRepository 自动实现\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">KeysetAwareRepository</code>Integration游标分页高性能列表分页游标 SQL 自动生成\n\n\n</p></section>\n<section style=\"margin:12px 0 20px;\"><section style=\"display:inline-block;min-width:100px;background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:12px 14px;text-align:center;margin:4px 6px 4px 0;\"><p style=\"margin:0;font-size:22px;font-weight:800;color:#1e6fff;\">9</p><p style=\"margin:4px 0 0;font-size:10px;color:#888;text-transform:uppercase;letter-spacing:.5px;\">核心 SPI 接口</p></section><section style=\"display:inline-block;min-width:100px;background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:12px 14px;text-align:center;margin:4px 6px 4px 0;\"><p style=\"margin:0;font-size:22px;font-weight:800;color:#1e6fff;\">30+</p><p style=\"margin:4px 0 0;font-size:10px;color:#888;text-transform:uppercase;letter-spacing:.5px;\">框架内置 JpqlFunction</p></section><section style=\"display:inline-block;min-width:100px;background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:12px 14px;text-align:center;margin:4px 6px 4px 0;\"><p style=\"margin:0;font-size:22px;font-weight:800;color:#1e6fff;\">7</p><p style=\"margin:4px 0 0;font-size:10px;color:#888;text-transform:uppercase;letter-spacing:.5px;\">DbmsDialect 方言实现</p></section><section style=\"display:inline-block;min-width:100px;background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:12px 14px;text-align:center;margin:4px 6px 4px 0;\"><p style=\"margin:0;font-size:22px;font-weight:800;color:#1e6fff;\">5+</p><p style=\"margin:4px 0 0;font-size:10px;color:#888;text-transform:uppercase;letter-spacing:.5px;\">ObjectBuilder 变体</p></section></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">20.2 JpqlFunction — 自定义函数注册</h2></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">这个 SPI 是什么</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">JpqlFunction</code> 是 Blaze-Persistence 最核心的扩展点。它让开发者在 JPQL 层面注册任意函数，框架在 SQL 渲染时调用函数的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">render()</code> 方法产出目标数据库的原生 SQL 片段。接口定义只有四个方法：</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">public interface JpqlFunction {<br/><br/>    boolean hasArguments();<br/><br/>    boolean hasParenthesesIfNoArguments();<br/><br/>    Class&lt;?&gt; getReturnType(Class&lt;?&gt; firstArgumentType);<br/><br/>    void render(FunctionRenderContext context);<br/>}</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 20-2 JpqlFunction 渲染调用时序</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">用户代码</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">CriteriaBuilder</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">ExpressionParser</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">FunctionRenderer</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">JpqlFunction</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">FunctionRenderContext</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">SQL Buffer</th></tr></table></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">Step 1: 定义自定义函数</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">public class PostgresArrayAggFunction implements JpqlFunction {<br/><br/>    @Override<br/>    public boolean hasArguments() {<br/>        return true;<br/>    }<br/><br/>    @Override<br/>    public boolean hasParenthesesIfNoArguments() {<br/>        return true;<br/>    }<br/><br/>    @Override<br/>    public Class&lt;?&gt; getReturnType(Class&lt;?&gt; firstArgType) {<br/>        return String.class;<br/>    }<br/><br/>    @Override<br/>    public void render(FunctionRenderContext ctx) {<br/>        ctx.addChunk(\"array_agg(\");<br/>        ctx.addArgument(0);     <span style=\"color:#6c7086;font-style:italic;\">// 渲染第一个参数</span><br/>        ctx.addChunk(\")\");<br/>    }<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">Step 2: 注册到 CriteriaBuilderConfiguration</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">CriteriaBuilderConfiguration config = Criteria.getDefault();<br/>config.registerFunction(<br/>    new JpqlFunctionGroup(\"array_agg\", new PostgresArrayAggFunction())<br/>);<br/>CriteriaBuilderFactory cbf = config.createCriteriaBuilderFactory(emf);</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">Step 3: 在查询中使用 + 输出 SQL</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">CriteriaBuilder&lt;Tuple&gt; cb = cbf.create(em, Tuple.class)<br/>    .from(Order.class, \"o\")<br/>    .select(\"o.customer.name\")<br/>    .select(\"FUNCTION('array_agg', o.product.name)\")<br/>    .groupBy(\"o.customer.name\");<br/><br/>System.out.println(cb.getQueryString());</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 生成的 JPQL:<br/>SELECT o.customer.name, array_agg(product_1.name)<br/>FROM Order o JOIN o.product product_1<br/>GROUP BY o.customer.name<br/><br/>-- PostgreSQL 原生 SQL:<br/>SELECT customer_1.name, array_agg(product_1.name)<br/>FROM orders o<br/>JOIN customers customer_1 ON o.customer_id = customer_1.id<br/>JOIN products product_1 ON o.product_id = product_1.id<br/>GROUP BY customer_1.name</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">框架自己怎么用：30+ 内置函数</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">Blaze-Persistence 自身通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">JpqlFunction</code> 注册了大量内置函数。这些函数覆盖集合运算、窗口函数、聚合增强、分页辅助等多个领域，且针对不同数据库有不同的渲染实现。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 20-3 框架内置 JpqlFunction 分类与 SQL 映射</p><p style=\"font-size:13px;color:#2b2b2b;line-height:2;margin:8px 0;\">\n\n集合运算函数\nSET_UNION → UNION / UNION ALL<br/>SET_INTERSECT → INTERSECT<br/>SET_EXCEPT → EXCEPT / MINUS\n\n\n窗口函数\nWINDOW_ROW_NUMBER → ROW_NUMBER()<br/>WINDOW_RANK → RANK()<br/>WINDOW_DENSE_RANK → DENSE_RANK()<br/>WINDOW_SUM/AVG/COUNT → OVER(...)\n\n\n聚合增强\nCOUNT_TUPLE → COUNT(DISTINCT a, b)<br/>GROUP_CONCAT → STRING_AGG / GROUP_CONCAT\n\n\n工具函数\nPAGE_POSITION → 子查询偏移量<br/>ENTITY_FUNCTION → 实体类型判定<br/>NULLFN → CAST(NULL AS type)<br/>PARAM → 参数占位渲染\n\n</p></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">以 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">GROUP_CONCAT</code> 为例——同一个 JPQL 函数调用，框架为不同数据库渲染完全不同的原生 SQL：</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 用户代码 — 与数据库无关:</span><br/>CriteriaBuilder&lt;Tuple&gt; cb = cbf.create(em, Tuple.class)<br/>    .from(Order.class, \"o\")<br/>    .select(\"o.customer.name\")<br/>    .select(\"GROUP_CONCAT(o.product.name SEPARATOR ',')\")<br/>    .groupBy(\"o.customer.name\");</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- PostgreSQL 渲染:<br/>SELECT c.name, STRING_AGG(p.name, ',')<br/>FROM orders o<br/>JOIN customers c ON o.customer_id = c.id<br/>JOIN products p ON o.product_id = p.id<br/>GROUP BY c.name<br/><br/>-- MySQL 渲染:<br/>SELECT c.name, GROUP_CONCAT(p.name SEPARATOR ',')<br/>FROM orders o<br/>JOIN customers c ON o.customer_id = c.id<br/>JOIN products p ON o.product_id = p.id<br/>GROUP BY c.name<br/><br/>-- Oracle 渲染:<br/>SELECT c.name, LISTAGG(p.name, ',') WITHIN GROUP (ORDER BY p.name)<br/>FROM orders o<br/>JOIN customers c ON o.customer_id = c.id<br/>JOIN products p ON o.product_id = p.id<br/>GROUP BY c.name<br/><br/>-- SQL Server 渲染:<br/>SELECT c.name, STRING_AGG(p.name, ',')<br/>FROM orders o<br/>JOIN customers c ON o.customer_id = c.id<br/>JOIN products p ON o.product_id = p.id<br/>GROUP BY c.name</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">Dogfooding 设计</strong>：JpqlFunction 不是\"给用户的附加功能\"。框架自身的窗口函数（<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">WINDOW_ROW_NUMBER</code>）、集合运算（<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">SET_UNION</code>）、聚合增强（<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">COUNT_TUPLE</code>）全部通过同一 SPI 实现。你的自定义函数与框架内置函数享有完全相同的渲染管线。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">20.3 JpqlMacro — 宏表达式</h2></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">这个 SPI 是什么</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">JpqlMacro</code> 工作在表达式解析的最前端——在 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">JpqlFunction</code> 查找之前。它不产出 SQL，而是将宏调用展开为新的 JPQL 表达式片段。接口只有一个方法：</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">public interface JpqlMacro {<br/><br/>    void render(FunctionRenderContext context);<br/>}</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 20-4 JpqlMacro 在表达式解析管线中的位置</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">JpqlMacro</p></section></td><td style=\"padding:0 2px;text-align:center;vertical-align:middle;width:24px;\"><p style=\"margin:0;font-size:18px;color:#1e6fff;line-height:1;\">→</p></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">render</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">用户表达式<br/>NOW()\"] --> LEXER[\"词法分析器</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">词法分析器</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">宏展开<br/>JpqlMacro.render()</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">展开后表达式<br/>CURRENT_TIMESTAMP</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">表达式解析树</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">JpqlFunction 查找<br/>（如有函数调用）</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">SQL 渲染器</p></section></td></tr></table></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">我们怎么用：NOW 时间戳宏</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">public class NowMacro implements JpqlMacro {<br/><br/>    @Override<br/>    public void render(FunctionRenderContext ctx) {<br/>        ctx.addChunk(\"CURRENT_TIMESTAMP\");<br/>    }<br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 注册宏</span><br/>config.registerMacro(\"NOW\", new NowMacro());</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 使用宏进行查询:</span><br/>CriteriaBuilder&lt;Order&gt; cb = cbf.create(em, Order.class, \"o\")<br/>    .where(\"o.createdAt\").ltExpression(\"NOW()\");<br/><br/>System.out.println(cb.getQueryString());</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 生成的 JPQL（宏展开后）:<br/>SELECT o<br/>FROM Order o<br/>WHERE o.createdAt &lt; CURRENT_TIMESTAMP<br/><br/>-- PostgreSQL 原生 SQL:<br/>SELECT o.*<br/>FROM orders o<br/>WHERE o.created_at &lt; CURRENT_TIMESTAMP</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">我们怎么用：多租户宏</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">public class CurrentTenantMacro implements JpqlMacro {<br/><br/>    @Override<br/>    public void render(FunctionRenderContext ctx) {<br/>        ctx.addChunk(\":currentTenantId\");<br/>    }<br/>}<br/><br/>config.registerMacro(\"CURRENT_TENANT\", new CurrentTenantMacro());<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 在任何查询中自动注入租户条件:</span><br/>CriteriaBuilder&lt;Order&gt; cb = cbf.create(em, Order.class, \"o\")<br/>    .where(\"o.tenantId\").eqExpression(\"CURRENT_TENANT()\")<br/>    .where(\"o.status\").eq(OrderStatus.ACTIVE);<br/><br/>cb.setParameter(\"currentTenantId\", SecurityContext.getTenantId());<br/>System.out.println(cb.getQueryString());</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 宏展开后生成的 JPQL:<br/>SELECT o<br/>FROM Order o<br/>WHERE o.tenantId = :currentTenantId<br/>  AND o.status = :param_0<br/><br/>-- PostgreSQL 原生 SQL:<br/>SELECT o.*<br/>FROM orders o<br/>WHERE o.tenant_id = ?<br/>  AND o.status = ?</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">框架自己怎么用：VIEW_ROOT 和 EMBEDDING_VIEW_ROOT</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">Entity View 中的子查询关联（<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@MappingCorrelated</code>）需要引用\"当前视图的根实体\"和\"嵌入视图的父实体\"。框架通过内置宏完成这一关联：</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 20-5 框架内置宏的展开逻辑</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">MACROS</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">VIEW_ROOT(attr)\"] -->|展开为| VRE[\"当前 Entity View<br/>根实体的关联路径</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">当前 Entity View<br/>根实体的关联路径</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">EMBEDDING_VIEW_ROOT(attr)\"] -->|展开为| EVRE[\"父级嵌入 View<br/>根实体的关联路径</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">父级嵌入 View<br/>根实体的关联路径</p></section></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">EXAMPLE</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">VIEW_ROOT(id)\"] -->|CatView 根实体| E1[\"cat.id</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">cat.id</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">VIEW_ROOT(owner.name)\"] -->|关联路径| E2[\"cat.owner.name</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">cat.owner.name</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">EMBEDDING_VIEW_ROOT(id)\"] -->|父 View 根| E3[\"parentCat.id</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">parentCat.id</p></section></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">用于 @MappingCorrelated<br/>子查询关联</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">用于嵌套 View 中<br/>引用外层实体</p></section></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 框架内部使用 VIEW_ROOT 宏的场景:</span><br/>@EntityView(Cat.class)<br/>public interface CatDetailView {<br/><br/>    @IdMapping<br/>    Long getId();<br/><br/>    String getName();<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// @MappingCorrelated 使用 VIEW_ROOT 宏引用根实体</span><br/>    @MappingCorrelated(<br/>        correlationBasis = \"VIEW_ROOT(id)\",<br/>        correlationExpression = \"kitten.parent.id = EMBEDDING_VIEW_ROOT(id)\",<br/>        correlationResult = \"kitten\"<br/>    )<br/>    List&lt;KittenView&gt; getKittens();<br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// VIEW_ROOT(id) 在宏展开阶段被替换为:  cat.id</span><br/><span style=\"color:#6c7086;font-style:italic;\">// EMBEDDING_VIEW_ROOT(id) 被替换为:   parentCat.id</span></p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 宏展开后最终生成的 SQL:<br/>SELECT c.id, c.name,<br/>       k.id AS kittens_id, k.name AS kittens_name<br/>FROM cats c<br/>LEFT JOIN cats k ON k.parent_id = c.id</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">20.4 DbmsDialect — 数据库方言扩展</h2></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">这个 SPI 是什么</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">DbmsDialect</code> 是 Blaze-Persistence 能够跨数据库工作的关键。每个方言实现了同一套接口，控制 CTE、窗口函数、分页、LATERAL JOIN、DML 等高级特性在不同数据库上的渲染策略。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 20-6 DbmsDialect 继承体系</p><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">DbmsDialect</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">&lt;&lt;interface&gt;&gt; · isCTE · isLateralJoin · isSetOperation · isWindowFunction …</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">DefaultDbmsDialect</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">通用默认实现</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">PostgreSQLDbmsDialect</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">WITH RECURSIVE · LATERAL JOIN · WINDOW 完整支持 · LIMIT / OFFSET</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">MySQLDbmsDialect</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">CTE 模拟 5.x / 原生 8.0 · 无 LATERAL / 8.0.14+ · WINDOW 8.0+ · LIMIT offset count</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">OracleDbmsDialect</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">WITH 子句 · LATERAL JOIN · 分析函数语法 · ROWNUM / FETCH FIRST</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">SQLServerDbmsDialect</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">WITH CTE · CROSS / OUTER APPLY · WINDOW 完整支持 · OFFSET FETCH</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">H2DbmsDialect</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">WITH 子句 · LATERAL 模拟 · WINDOW 部分支持 · LIMIT / OFFSET</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">DB2DbmsDialect</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">WITH CTE · LATERAL JOIN · OLAP 函数 · FETCH FIRST n ROWS</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">完整代码：同一 CTE API，不同 SQL 输出</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 用户代码 — 完全与数据库无关:</span><br/>@CTE<br/>@Entity<br/>public class OrderSummaryCTE {<br/>    @Id Long id;<br/>    String customerName;<br/>    BigDecimal totalAmount;<br/>}<br/><br/>CriteriaBuilder&lt;Tuple&gt; cb = cbf.create(em, Tuple.class)<br/>    .with(OrderSummaryCTE.class)<br/>        .from(Order.class, \"o\")<br/>        .bind(\"id\").select(\"o.id\")<br/>        .bind(\"customerName\").select(\"o.customer.name\")<br/>        .bind(\"totalAmount\").select(\"o.totalAmount\")<br/>    .end()<br/>    .from(OrderSummaryCTE.class, \"s\")<br/>    .select(\"s.customerName\")<br/>    .select(\"SUM(s.totalAmount)\")<br/>    .groupBy(\"s.customerName\")<br/>    .orderByAsc(\"s.customerName\");<br/><br/>System.out.println(cb.getQueryString());</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 20-7 相同 CTE API 在不同数据库上的 SQL 渲染对比</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">CriteriaBuilder<br/>with(OrderSummaryCTE.class)<br/>.from(Order.class)<br/>.bind(...).select(...)</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">from</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">5</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">7</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">SELECT</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">FROM</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">o</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">id</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">PostgreSQL<br/>DbmsDialect</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">MySQL 5.7<br/>DbmsDialect</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Oracle<br/>DbmsDialect</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">WITH OrderSummaryCTE AS (<br/>  SELECT ...<br/>)<br/>SELECT ... FROM OrderSummaryCTE</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">SELECT ... FROM (<br/>  SELECT ... FROM orders o<br/>) AS OrderSummaryCTE</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">WITH OrderSummaryCTE AS (<br/>  SELECT o.id AS id, ...<br/>)<br/>SELECT ...</p></section></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- PostgreSQL 输出（原生 CTE 支持）:<br/>WITH OrderSummaryCTE(id, customerName, totalAmount) AS (<br/>    SELECT o.id, c.name, o.total_amount<br/>    FROM orders o<br/>    JOIN customers c ON o.customer_id = c.id<br/>)<br/>SELECT s.customerName, SUM(s.totalAmount)<br/>FROM OrderSummaryCTE s<br/>GROUP BY s.customerName<br/>ORDER BY s.customerName ASC<br/><br/>-- MySQL 5.7 输出（无 CTE — 自动降级为派生表）:<br/>SELECT s.customerName, SUM(s.totalAmount)<br/>FROM (<br/>    SELECT o.id AS id, c.name AS customerName, o.total_amount AS totalAmount<br/>    FROM orders o<br/>    JOIN customers c ON o.customer_id = c.id<br/>) AS OrderSummaryCTE s<br/>GROUP BY s.customerName<br/>ORDER BY s.customerName ASC<br/><br/>-- MySQL 8.0+ 输出（原生 CTE）:<br/>WITH OrderSummaryCTE(id, customerName, totalAmount) AS (<br/>    SELECT o.id, c.name, o.total_amount<br/>    FROM orders o<br/>    JOIN customers c ON o.customer_id = c.id<br/>)<br/>SELECT s.customerName, SUM(s.totalAmount)<br/>FROM OrderSummaryCTE s<br/>GROUP BY s.customerName<br/>ORDER BY s.customerName ASC<br/><br/>-- Oracle 输出:<br/>WITH OrderSummaryCTE AS (<br/>    SELECT o.id AS id, c.name AS customerName, o.total_amount AS totalAmount<br/>    FROM orders o<br/>    JOIN customers c ON o.customer_id = c.id<br/>)<br/>SELECT s.customerName, SUM(s.totalAmount)<br/>FROM OrderSummaryCTE s<br/>GROUP BY s.customerName<br/>ORDER BY s.customerName ASC</p></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n\n\n特性PostgreSQLMySQL 5.xMySQL 8.0+OracleSQL Server\n\n\nCTEWITH ... AS派生表模拟WITH ... ASWITH ... ASWITH ... AS\n递归 CTEWITH RECURSIVE不支持WITH RECURSIVECONNECT BY / WITHWITH ... AS\nLATERAL JOINLATERAL不支持LATERAL (8.0.14+)LATERALCROSS/OUTER APPLY\n窗口函数完整支持不支持完整支持分析函数语法完整支持\n分页LIMIT/OFFSETLIMIT m,nLIMIT m,nFETCH FIRSTOFFSET FETCH\nDML + JOINUPDATE FROMUPDATE JOINUPDATE JOINMERGE INTOUPDATE FROM\n\n\n</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">分页的方言差异</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 用户代码:</span><br/>PaginatedCriteriaBuilder&lt;Tuple&gt; pcb = cbf.create(em, Tuple.class)<br/>    .from(Order.class, \"o\")<br/>    .select(\"o.id\").select(\"o.customer.name\")<br/>    .orderByAsc(\"o.id\")<br/>    .page(0, 20);    <span style=\"color:#6c7086;font-style:italic;\">// 第一页，20 条</span></p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- PostgreSQL:<br/>SELECT o.id, c.name FROM orders o<br/>JOIN customers c ON o.customer_id = c.id<br/>ORDER BY o.id ASC<br/>LIMIT 20 OFFSET 0<br/><br/>-- Oracle 12c+:<br/>SELECT o.id, c.name FROM orders o<br/>JOIN customers c ON o.customer_id = c.id<br/>ORDER BY o.id ASC<br/>FETCH FIRST 20 ROWS ONLY<br/><br/>-- SQL Server:<br/>SELECT o.id, c.name FROM orders o<br/>JOIN customers c ON o.customer_id = c.id<br/>ORDER BY o.id ASC<br/>OFFSET 0 ROWS FETCH NEXT 20 ROWS ONLY<br/><br/>-- MySQL:<br/>SELECT o.id, c.name FROM orders o<br/>JOIN customers c ON o.customer_id = c.id<br/>ORDER BY o.id ASC<br/>LIMIT 20</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">20.5 ObjectBuilder — 结果映射扩展</h2></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">这个 SPI 是什么</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">ObjectBuilder<T></code> 定义了如何将查询返回的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">Object[]</code> 元组转换为目标对象。它是 Entity View 代理构建的底层基础设施。</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">public interface ObjectBuilder&lt;T&gt; {<br/><br/>    T build(Object[] tuple);<br/><br/>    List&lt;T&gt; buildList(List&lt;T&gt; list);<br/>}</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 20-8 ObjectBuilder 在查询结果转换管线中的位置</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">FRAMEWORK</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">ViewTypeObjectBuilder\"] --> PROXY[\"创建代理实例<br/>CatView_$$_impl</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">创建代理实例<br/>CatView_$$_impl</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">初始化脏跟踪快照</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">递归构建嵌套 View</p></section></td></tr></table></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">CUSTOM</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">OrderDtoBuilder\"] --> DTO[\"构建扁平 DTO</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">构建扁平 DTO</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">计算派生字段</p></section></td></tr></table></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">ObjectBuilder<T><br/>.build(tuple)</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">JDBC ResultSet<br/>原始行数据\"] --> TUPLE[\"Object[] 元组<br/>[1, 'Alice', 299.50]</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Object[] 元组<br/>[1, 'Alice', 299.50]</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">目标对象<br/>DTO / Entity View 代理</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">我们怎么用：自定义 DTO 构建</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">public class OrderDtoBuilder implements ObjectBuilder&lt;OrderDto&gt; {<br/><br/>    @Override<br/>    public OrderDto build(Object[] tuple) {<br/>        return new OrderDto(<br/>            (String) tuple[0],       <span style=\"color:#6c7086;font-style:italic;\">// customerName</span><br/>            (BigDecimal) tuple[1]    <span style=\"color:#6c7086;font-style:italic;\">// totalAmount</span><br/>        );<br/>    }<br/><br/>    @Override<br/>    public List&lt;OrderDto&gt; buildList(List&lt;OrderDto&gt; list) {<br/>        return list;  <span style=\"color:#6c7086;font-style:italic;\">// 可在此做排序、去重等后处理</span><br/>    }<br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 使用 ObjectBuilder:</span><br/>CriteriaBuilder&lt;OrderDto&gt; cb = cbf.create(em, Tuple.class)<br/>    .from(Order.class, \"o\")<br/>    .selectNew(new OrderDtoBuilder())<br/>        .with(\"o.customer.name\")<br/>        .with(\"SUM(o.totalAmount)\")<br/>    .end()<br/>    .groupBy(\"o.customer.name\")<br/>    .orderByDesc(\"SUM(o.totalAmount)\");<br/><br/>List&lt;OrderDto&gt; results = cb.getResultList();</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 生成的 SQL:<br/>SELECT c.name, SUM(o.total_amount)<br/>FROM orders o<br/>JOIN customers c ON o.customer_id = c.id<br/>GROUP BY c.name<br/>ORDER BY SUM(o.total_amount) DESC<br/><br/>-- ResultSet 中的每一行 Object[] 被 OrderDtoBuilder.build() 转换为 OrderDto</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">框架自己怎么用：ViewTypeObjectBuilder</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 20-9 ViewTypeObjectBuilder 递归构建嵌套 View</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">0</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">1</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">id</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">2</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">3</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">ResultSet 元组:<br/>[1, 'Tom', 2, 'Jerry', 'Science']</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">CatViewObjectBuilder<br/>取 tuple[0..1]</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">CatView<br/>{ id=1, name='Tom' }</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">OwnerViewObjectBuilder<br/>取 tuple[2..3]</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">OwnerView<br/>{ id=2, name='Jerry' }</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">字段提取<br/>取 tuple[4]</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">department = 'Science'</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">组装: CatView<br/>{ id=1, name='Tom',<br/>  owner: OwnerView{2, 'Jerry'},<br/>  department: 'Science' }</p></section></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 框架内部: ViewTypeObjectBuilder 的核心逻辑（简化）</span><br/>class ViewTypeObjectBuilder implements ObjectBuilder&lt;Object&gt; {<br/><br/>    private final ProxyFactory proxyFactory;<br/>    private final int[] tupleMapping;<br/>    private final ObjectBuilder&lt;?&gt;[] nestedBuilders;<br/><br/>    @Override<br/>    public Object build(Object[] tuple) {<br/>        Object proxy = proxyFactory.create(tupleMapping.length);<br/>        for (int i = 0; i &lt; tupleMapping.length; i++) {<br/>            int tupleIndex = tupleMapping[i];<br/>            if (nestedBuilders[i] != null) {<br/>                proxy.$$_setAttribute(i,<br/>                    nestedBuilders[i].build(tuple));<br/>            } else {<br/>                proxy.$$_setAttribute(i, tuple[tupleIndex]);<br/>            }<br/>        }<br/>        proxy.$$_initDirtyTracker();<br/>        return proxy;<br/>    }<br/>}</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">20.6 EntityViewListener — 视图生命周期钩子</h2></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">这个 SPI 是什么</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityViewListener</code> 在 Entity View 的创建、更新、删除操作前后触发，提供 AOP 风格的横切逻辑注入点。它的注解生命周期与 JPA 实体生命周期一一对应：<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@PrePersist</code> → <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@PreCreate</code>，<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@PreUpdate</code> → <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@PreUpdate</code>，<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@PreRemove</code> → <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@PreRemove</code>。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 20-10 Entity View CRUD 生命周期与 Listener 钩子</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">应用代码</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">EntityViewManager</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">EntityViewListener</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">EntityManager</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">数据库</th></tr></table><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 创建流程</p><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 更新流程</p><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 删除流程</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">我们怎么用：审计 Listener</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 定义可审计视图接口</span><br/>public interface AuditableView {<br/>    void setCreatedAt(Instant createdAt);<br/>    void setCreatedBy(String user);<br/>    void setUpdatedAt(Instant updatedAt);<br/>    void setUpdatedBy(String user);<br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 审计 Listener</span><br/>@ViewListener<br/>public class AuditViewListener implements EntityViewListener {<br/><br/>    @PrePersist<br/>    public void onPrePersist(Object view) {<br/>        if (view instanceof AuditableView av) {<br/>            av.setCreatedAt(Instant.now());<br/>            av.setCreatedBy(SecurityContext.getCurrentUser());<br/>            av.setUpdatedAt(Instant.now());<br/>            av.setUpdatedBy(SecurityContext.getCurrentUser());<br/>        }<br/>    }<br/><br/>    @PreUpdate<br/>    public void onPreUpdate(Object view) {<br/>        if (view instanceof AuditableView av) {<br/>            av.setUpdatedAt(Instant.now());<br/>            av.setUpdatedBy(SecurityContext.getCurrentUser());<br/>        }<br/>    }<br/><br/>    @PreRemove<br/>    public boolean onPreRemove(Object view) {<br/>        AuditLog.record(\"DELETE\",<br/>            view.getClass().getSimpleName(),<br/>            ((Identifiable) view).getId(),<br/>            SecurityContext.getCurrentUser());<br/>        return true;   <span style=\"color:#6c7086;font-style:italic;\">// false → 取消删除操作</span><br/>    }<br/><br/>    @PostUpdate<br/>    public void onPostUpdate(Object view) {<br/>        EventBus.publish(new EntityUpdatedEvent(<br/>            view.getClass().getSimpleName(),<br/>            ((Identifiable) view).getId()));<br/>    }<br/>}</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- @PrePersist 注入后实际执行的 SQL:<br/>INSERT INTO orders (id, customer_name, total_amount,<br/>                    created_at, created_by,<br/>                    updated_at, updated_by)<br/>VALUES (?, ?, ?,<br/>        '2026-04-21T10:30:00Z', 'admin',<br/>        '2026-04-21T10:30:00Z', 'admin')<br/><br/>-- @PreUpdate 注入后实际执行的 SQL:<br/>UPDATE orders<br/>SET customer_name = ?, total_amount = ?,<br/>    updated_at = '2026-04-21T14:15:00Z',<br/>    updated_by = 'admin'<br/>WHERE id = ?</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">框架自己怎么用</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 20-11 框架内部 Listener 用途</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">INTERNAL</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">脏跟踪 Listener<br/>DirtyTrackingListener</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">级联传播 Listener<br/>CascadePropagationListener</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">版本校验 Listener<br/>VersionValidationListener</p></section></td></tr></table></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">@PreCreate:<br/>标记所有字段为 NEW</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">@PostLoad:<br/>记录初始状态快照</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">@PreUpdate:<br/>递归检查子 View 变更</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">@PreRemove:<br/>级联删除嵌套 View</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">@PreUpdate:<br/>校验 @Version 一致<br/>不一致 → OptimisticLockException</p></section></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">20.7 ViewFilter — 视图过滤器</h2></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">这个 SPI 是什么</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@ViewFilter</code> 为 Entity View 定义可复用的命名过滤条件。查询时按名称激活——适合软删除、多租户、状态过滤等横切逻辑。<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">ViewFilter</code> 是纯用户扩展点——框架内部不使用它。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 20-12 ViewFilter 应用管线</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">PIPELINE</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">基础 CriteriaBuilder<br/>SELECT o FROM Order o\"] --> F1[\"应用 activeOnly<br/>追加: AND o.deleted = false</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">应用 activeOnly<br/>追加: AND o.deleted = false</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">应用 tenant<br/>追加: AND o.tenantId = :tid</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">SELECT o FROM Order o<br/>WHERE o.deleted = false<br/>AND o.tenantId = :tid</p></section></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">EntityViewSetting<br/>.addViewFilter('activeOnly')<br/>.addViewFilter('tenant')</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">@ViewFilter(name='activeOnly',<br/>  value='deleted = false')<br/>@ViewFilter(name='tenant',<br/>  value='tenantId = :tid')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">合并过滤条件<br/>追加到 WHERE 子句</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">最终 SQL</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">完整代码：软删除 + 多租户过滤</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// Step 1: 定义 Entity View，声明过滤器</span><br/>@EntityView(Order.class)<br/>@ViewFilter(name = \"activeOnly\", value = \"deleted = false\")<br/>@ViewFilter(name = \"currentTenant\", value = \"tenantId = :tenantId\")<br/>public interface OrderView {<br/><br/>    @IdMapping<br/>    Long getId();<br/><br/>    String getCustomerName();<br/><br/>    BigDecimal getTotalAmount();<br/><br/>    OrderStatus getStatus();<br/><br/>    boolean isDeleted();<br/>}</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// Step 2: 查询时激活过滤器</span><br/>EntityViewSetting&lt;OrderView, CriteriaBuilder&lt;OrderView&gt;&gt; setting =<br/>    EntityViewSetting.create(OrderView.class);<br/><br/>setting.addViewFilter(\"activeOnly\");<br/>setting.addViewFilter(\"currentTenant\");<br/>setting.addOptionalParameter(\"tenantId\", currentTenantId);<br/><br/>CriteriaBuilder&lt;OrderView&gt; cb = cbf.create(em, Order.class);<br/>List&lt;OrderView&gt; orders = evm.applySetting(setting, cb)<br/>    .getResultList();</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 生成的 JPQL（两个过滤器合并后）:<br/>SELECT o<br/>FROM Order o<br/>WHERE o.deleted = false<br/>  AND o.tenantId = :tenantId<br/><br/>-- PostgreSQL 原生 SQL:<br/>SELECT o.id, o.customer_name, o.total_amount, o.status, o.deleted<br/>FROM orders o<br/>WHERE o.deleted = false<br/>  AND o.tenant_id = ?</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">ViewFilterProvider — 动态过滤参数</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ViewFilterProvider: 无需手动设置参数，由 Provider 自动注入</span><br/>public class TenantFilterProvider implements ViewFilterProvider {<br/><br/>    @Override<br/>    public String getFilterName() {<br/>        return \"currentTenant\";<br/>    }<br/><br/>    @Override<br/>    public Map&lt;String, Object&gt; getFilterParameters() {<br/>        return Map.of(\"tenantId\", SecurityContext.getTenantId());<br/>    }<br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 注册后，activeOnly 过滤器自动生效，无需手动 addViewFilter:</span><br/>EntityViewSetting&lt;OrderView, CriteriaBuilder&lt;OrderView&gt;&gt; setting =<br/>    EntityViewSetting.create(OrderView.class);<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// tenantId 参数由 TenantFilterProvider 自动注入</span><br/>List&lt;OrderView&gt; orders = evm.applySetting(setting, cb)<br/>    .getResultList();</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">20.8 CriteriaBuilderConfigurationContributor — 启动时扩展</h2></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">这个 SPI 是什么</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CriteriaBuilderConfigurationContributor</code> 基于 Java <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">ServiceLoader</code> 机制，让扩展模块在框架启动时自动注册自定义函数、方言、宏等配置——零显式代码。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 20-13 ServiceLoader 自动发现与配置流程</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Criteria</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">getDefault</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">META</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">INF</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">blaze</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">persistence</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">应用启动<br/>Criteria.getDefault()\"] --> SL[\"ServiceLoader.load(<br/>CriteriaBuilderConfiguration<br/>Contributor.class)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">ServiceLoader.load(<br/>CriteriaBuilderConfiguration<br/>Contributor.class)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">扫描 classpath 所有 JAR<br/>META-INF/services/</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">发现: HibernateContributor<br/>blaze-persistence-integration-hibernate</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">发现: EclipseLinkContributor<br/>blaze-persistence-integration-eclipselink</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">发现: MyAppContributor<br/>用户自定义</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">调用 contribute(config)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">注册 Hibernate 特定<br/>JPA Provider 实现</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">注册 EclipseLink<br/>适配器</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">注册 array_agg<br/>ST_DISTANCE 等业务函数</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">CriteriaBuilderFactory<br/>就绪 — 所有扩展已加载</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">框架自己怎么用</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">Blaze-Persistence 的 Hibernate 集成模块通过此机制自动注册 Hibernate 特有的 JPA Provider 实现。开发者只要引入 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">blaze-persistence-integration-hibernate-5.x</code> Maven 依赖，ServiceLoader 会自动发现 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">HibernateRegistrationContributor</code> 并注册 Hibernate Provider——无需手动配置。</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">我们怎么用：自定义 Contributor</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// Step 1: 实现 Contributor</span><br/>public class MyAppContributor<br/>        implements CriteriaBuilderConfigurationContributor {<br/><br/>    @Override<br/>    public void contribute(CriteriaBuilderConfiguration config) {<br/>        <span style=\"color:#6c7086;font-style:italic;\">// 注册自定义 JPQL 函数</span><br/>        config.registerFunction(<br/>            new JpqlFunctionGroup(\"array_agg\",<br/>                new PostgresArrayAggFunction()));<br/>        config.registerFunction(<br/>            new JpqlFunctionGroup(\"ts_rank\",<br/>                new PostgresTsRankFunction()));<br/><br/>        <span style=\"color:#6c7086;font-style:italic;\">// 注册自定义宏</span><br/>        config.registerMacro(\"CURRENT_TENANT\",<br/>            new CurrentTenantMacro());<br/>        config.registerMacro(\"NOW\",<br/>            new NowMacro());<br/>    }<br/>}</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\"># Step 2: 创建 ServiceLoader 配置文件</span><br/><span style=\"color:#6c7086;font-style:italic;\"># 文件路径: META-INF/services/com.blazebit.persistence.spi.CriteriaBuilderConfigurationContributor</span><br/><span style=\"color:#6c7086;font-style:italic;\"># 文件内容（每行一个全限定类名）:</span><br/>com.example.MyAppContributor</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// Step 3: 零配置 — 应用启动时自动发现</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 无需任何额外代码！ServiceLoader 自动调用 contribute():</span><br/><br/>CriteriaBuilderConfiguration config = Criteria.getDefault();<br/><span style=\"color:#6c7086;font-style:italic;\">//  ↑ 此时 MyAppContributor.contribute(config) 已被调用</span><br/><span style=\"color:#6c7086;font-style:italic;\">//    array_agg, ts_rank 函数已注册</span><br/><span style=\"color:#6c7086;font-style:italic;\">//    CURRENT_TENANT, NOW 宏已注册</span><br/><br/>CriteriaBuilderFactory cbf = config.createCriteriaBuilderFactory(emf);<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 直接使用注册的函数:</span><br/>CriteriaBuilder&lt;Tuple&gt; cb = cbf.create(em, Tuple.class)<br/>    .from(Order.class, \"o\")<br/>    .select(\"FUNCTION('array_agg', o.product.name)\")<br/>    .groupBy(\"o.customer.name\");</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 自动注册后直接可用的查询:<br/>SELECT array_agg(p.name)<br/>FROM orders o<br/>JOIN products p ON o.product_id = p.id<br/>GROUP BY o.customer_name</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">ServiceLoader 的威力</strong>：将函数/宏/方言打包为独立 JAR，消费方只需添加 Maven 依赖——ServiceLoader 自动发现并注册所有扩展。这正是 Blaze-Persistence 自身 Hibernate/EclipseLink 集成模块的工作方式。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">20.9 Spring Data Repository 扩展</h2></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">这个 SPI 是什么</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">Blaze-Persistence 在 Spring Data 层面提供三个核心扩展接口，让 Repository 具备 Entity View 感知能力、动态查询能力和游标分页能力。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 20-14 Spring Data Repository 扩展继承体系</p><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">OrderViewRepository</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">&lt;&lt;用户定义&gt;&gt; · findByStatus · findByTotalAmountGreaterThan</p></section></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 20-15 Spring Data 自动代理生成流程</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Blaze</p></section></td><td style=\"padding:0 2px;text-align:center;vertical-align:middle;width:24px;\"><p style=\"margin:0;font-size:18px;color:#1e6fff;line-height:1;\">→</p></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Persistence</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">OrderViewRepository<br/>接口定义\"] --> PROXY[\"Spring Data<br/>代理工厂</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Spring Data<br/>代理工厂</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">检测: extends<br/>EntityViewRepository?</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Blaze-Persistence<br/>SimpleEntityViewRepository<br/>自动生成实现</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">标准 JPA<br/>SimpleJpaRepository</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">注入<br/>CriteriaBuilderFactory<br/>EntityViewManager</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Repository Bean<br/>可用于 @Autowired</p></section></td></tr></table></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">完整代码：Repository 定义</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">public interface OrderViewRepository<br/>        extends EntityViewRepository&lt;OrderView, Long&gt;,<br/>                EntityViewSpecificationExecutor&lt;OrderView, Long&gt;,<br/>                KeysetAwareRepository&lt;OrderView, Long&gt; {<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// 派生查询 — Spring Data 自动解析方法名:</span><br/>    List&lt;OrderView&gt; findByStatusAndTotalAmountGreaterThan(<br/>        OrderStatus status, BigDecimal minAmount);<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// 游标分页:</span><br/>    KeysetAwarePage&lt;OrderView&gt; findAll(Pageable pageable);<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// 自定义 JPQL:</span><br/>    @Query(\"SELECT o FROM Order o WHERE o.customer.name LIKE :keyword\")<br/>    List&lt;OrderView&gt; searchByCustomerName(<br/>        @Param(\"keyword\") String keyword);<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">用法 1：派生查询</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">List&lt;OrderView&gt; results = repo.findByStatusAndTotalAmountGreaterThan(<br/>    OrderStatus.CONFIRMED, new BigDecimal(\"100.00\"));</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- Spring Data 自动解析方法名生成:<br/>SELECT o.id, o.customer_name, o.total_amount, o.status<br/>FROM orders o<br/>WHERE o.status = ?<br/>  AND o.total_amount &gt; ?<br/>-- 参数: ['CONFIRMED', 100.00]</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">用法 2：Specification 组合查询</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 定义 Specification:</span><br/>class OrderSpecifications {<br/>    static Specification&lt;Order&gt; hasStatus(OrderStatus s) {<br/>        return (root, query, cb) -&gt;<br/>            cb.equal(root.get(\"status\"), s);<br/>    }<br/><br/>    static Specification&lt;Order&gt; totalGreaterThan(BigDecimal min) {<br/>        return (root, query, cb) -&gt;<br/>            cb.greaterThan(root.get(\"totalAmount\"), min);<br/>    }<br/><br/>    static Specification&lt;Order&gt; customerNameLike(String keyword) {<br/>        return (root, query, cb) -&gt;<br/>            cb.like(root.get(\"customer\").get(\"name\"),<br/>                    \"%\" + keyword + \"%\");<br/>    }<br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 组合 Specification:</span><br/>Page&lt;OrderView&gt; page = repo.findAll(<br/>    hasStatus(CONFIRMED)<br/>        .and(totalGreaterThan(new BigDecimal(\"100\")))<br/>        .and(customerNameLike(\"Alice\")),<br/>    PageRequest.of(0, 20, Sort.by(\"totalAmount\").descending())<br/>);</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 三个 Specification 组合后生成:<br/>SELECT o.id, o.customer_name, o.total_amount, o.status<br/>FROM orders o<br/>JOIN customers c ON o.customer_id = c.id<br/>WHERE o.status = ?<br/>  AND o.total_amount &gt; ?<br/>  AND c.name LIKE ?<br/>ORDER BY o.total_amount DESC<br/>LIMIT 20 OFFSET 0<br/>-- 参数: ['CONFIRMED', 100.00, '%Alice%']</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">用法 3：游标分页（Keyset Pagination）</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 第一页:</span><br/>KeysetAwarePage&lt;OrderView&gt; firstPage = repo.findAll(<br/>    new KeysetPageRequest(null, Sort.by(\"id\"), 20));<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 下一页 — 基于游标，不使用 OFFSET:</span><br/>KeysetAwarePage&lt;OrderView&gt; nextPage = repo.findAll(<br/>    firstPage.nextPageable());</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 第一页:<br/>SELECT o.id, o.customer_name, o.total_amount, o.status<br/>FROM orders o<br/>ORDER BY o.id ASC<br/>LIMIT 20<br/><br/>-- 第二页（游标分页，避免 OFFSET）:<br/>SELECT o.id, o.customer_name, o.total_amount, o.status<br/>FROM orders o<br/>WHERE o.id &gt; ?              -- 上一页最后一条的 id<br/>ORDER BY o.id ASC<br/>LIMIT 20<br/>-- 参数: [lastId]          -- 无 OFFSET！O(1) 性能</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">游标分页 vs OFFSET 分页</strong>：<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">OFFSET 10000</code> 需要数据库扫描前 10000 行后丢弃；游标分页用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">WHERE id > ?</code> 直接定位，性能恒定 O(1)，不随页码增长而下降。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">20.10 框架自用全景图</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">最后，用一张全景图展示 Blaze-Persistence 如何 Dogfooding 自己的扩展体系——每个扩展点都先被框架自身验证使用，再开放给开发者。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 20-16 框架自用全景：查询生命周期 × 扩展点</p><p style=\"font-size:13px;color:#2b2b2b;line-height:2;margin:8px 0;\">\n\n① 查询构建\nCriteriaBuilder API → ExpressionParser\n\n→\n\n② JpqlMacro\n框架: VIEW_ROOT, EMBEDDING_VIEW_ROOT\n用户: CURRENT_TENANT, NOW\n\n→\n\n③ JpqlFunction\n框架: 30+ 内置<br/>SET_UNION, WINDOW_ROW_NUMBER …\n用户: array_agg, ts_rank …\n\n→\n\n④ DbmsDialect\n框架: 7 方言<br/>PG / MySQL / Oracle …\n用户: 自定义方言覆盖\n\n→\n\n⑤ JDBC\n执行 SQL<br/>获取 ResultSet\n\n→\n\n⑥ ObjectBuilder\n框架: ViewType / Tuple / FlatView\n用户: OrderDtoBuilder\n\n→\n\n⑦ ViewListener\n框架: DirtyTracking, Cascade, Version\n用户: Audit, Events\n\n→\n\n⑧ 结果\nEntity View / DTO\n\n</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 20-17 框架内置 JpqlFunction 完整注册清单</p><p style=\"font-size:13px;color:#2b2b2b;line-height:2;margin:8px 0;\">\n\n集合运算 (5)\nSET_UNION<br/>SET_UNION_ALL<br/>SET_INTERSECT<br/>SET_INTERSECT_ALL<br/>SET_EXCEPT\n\n\n窗口函数 (10)\nWINDOW_ROW_NUMBER<br/>WINDOW_RANK<br/>WINDOW_DENSE_RANK<br/>WINDOW_NTILE<br/>WINDOW_LEAD / LAG<br/>WINDOW_SUM / AVG<br/>WINDOW_MIN / MAX\n\n\n聚合增强 (5)\nCOUNT_TUPLE<br/>GROUP_CONCAT<br/>WINDOW_COUNT<br/>WINDOW_FIRST_VALUE<br/>WINDOW_LAST_VALUE\n\n\n工具函数 (10+)\nPAGE_POSITION<br/>ENTITY_FUNCTION<br/>NULLFN / PARAM<br/>CAST_TYPE / TREAT_TYPE<br/>SUBQUERY / ALIAS<br/>COLUMN_TRUNC / EXIST\n\n</p></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n\n\n扩展点框架内部实现数框架自用场景开发者扩展场景\n\n\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">JpqlFunction</code>30+集合运算、窗口函数、聚合增强、分页辅助PostgreSQL array_agg、全文搜索 ts_rank、GIS 函数\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">JpqlMacro</code>2VIEW_ROOT / EMBEDDING_VIEW_ROOT 关联子查询租户 ID、审计用户、时间戳宏\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">DbmsDialect</code>7PostgreSQL / MySQL / Oracle / SQL Server / H2 / DB2 + Default自定义方言覆盖\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">ObjectBuilder</code>5+ViewType / Tuple / FlatView / Collection / Subquery 构建器自定义 DTO 构建器\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityViewListener</code>3脏跟踪初始化、级联传播、乐观锁版本校验审计日志、事件发布、自定义校验\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">ViewFilter</code>0纯用户扩展点（框架不自用）软删除、多租户、状态过滤\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">ConfigContributor</code>3+Hibernate / EclipseLink / DataNucleus Provider 集成注册自动注册自定义函数/方言包\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">Repository 扩展</code>4SimpleEntityViewRepository 自动实现派生查询、Specification 组合、游标分页\n\n\n</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 20-18 Dogfooding 设计哲学</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">设计哲学: Dogfooding<br/>框架自己是第一个用户</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">JpqlFunction<br/>框架先用它实现<br/>30+ 内置函数<br/>才开放给开发者</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">DbmsDialect<br/>框架先用它适配<br/>7 种数据库<br/>才允许用户覆盖</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">ObjectBuilder<br/>框架先用它构建<br/>Entity View 代理<br/>才暴露为扩展接口</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">ConfigContributor<br/>框架先用它注册<br/>JPA Provider<br/>才开放为自动发现</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">EntityViewListener<br/>框架先用它做<br/>脏跟踪和级联<br/>才开放生命周期钩子</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">结果: 每个扩展点都经过<br/>框架自身的严格验证<br/>开发者使用的 SPI<br/>与框架内核完全一致<br/>— 没有二等公民</p></section></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff22;border-radius:10px;padding:20px 22px;margin:36px 0 16px;\"><p style=\"font-size:18px;font-weight:700;color:#1e6fff;margin:0 0 12px;\">📋 本章小结</p><ul style=\"margin:8px 0 12px 20px;color:#2b2b2b;\"><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">JpqlFunction</strong> 让我们在 JPQL 层面注册自定义函数——<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">render()</code> 方法产出原生 SQL。框架自身用它实现了 30+ 内置函数（SET_UNION、WINDOW_ROW_NUMBER、GROUP_CONCAT 等），且 GROUP_CONCAT 在 PostgreSQL、MySQL、Oracle、SQL Server 上分别渲染为 STRING_AGG、GROUP_CONCAT、LISTAGG、STRING_AGG</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">JpqlMacro</strong> 在表达式解析前完成宏展开——比 JpqlFunction 更早介入。框架用 VIEW_ROOT / EMBEDDING_VIEW_ROOT 实现 Entity View 子查询关联；开发者可注册 CURRENT_TENANT、NOW 等业务宏</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">DbmsDialect</strong> 是跨数据库的枢纽——同一 CTE API，PostgreSQL 输出 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">WITH ... AS</code>，MySQL 5.7 降级为派生表，Oracle 用列别名语法。分页、窗口函数、LATERAL JOIN、DML + JOIN 同理</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">ObjectBuilder</strong> 将 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">Object[]</code> 元组映射为目标对象——框架的 ViewTypeObjectBuilder 负责创建 Entity View 代理、初始化脏跟踪、递归构建嵌套 View</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">EntityViewListener</strong> 提供 @PreCreate / @PreUpdate / @PreRemove 等生命周期钩子——框架内部用于脏跟踪和级联传播，开发者用于审计、事件发布</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">ViewFilter</strong> 是纯用户扩展点——通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@ViewFilter</code> 注解定义命名过滤器，查询时按名称激活，适合软删除和多租户</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">ConfigurationContributor</strong> 通过 ServiceLoader 实现零配置自动注册——将函数和宏打包为 JAR，消费方只需添加 Maven 依赖</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">Spring Data Repository 扩展</strong> 让 Repository 具备 Entity View 感知、Specification 动态查询、游标分页能力，生成高效的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">WHERE id > ?</code> 分页 SQL</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">Dogfooding 设计哲学</strong>：每个扩展点都先被框架自身使用验证，再开放给开发者——没有二等公民</li></ul><p style=\"font-size:13px;color:#888;margin-top:10px;padding-top:10px;border-top:1px solid #e5e7eb;\">下一章 <span style=\"color:#1e6fff;\">第 21 章 · SQL 优化与实战模式</span> 将前 20 章的知识融会贯通——用 Entity View 精确投影消灭 SELECT *，用 Keyset 分页替代 OFFSET，用 CTE + 窗口函数构建高性能报表，用 @ViewFilter 实现透明的软删除和多租户。</p></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">© 2026 图解 Blaze-Persistence · 第 20 章</p></section>";
  await page.waitForSelector('.ProseMirror', { timeout: 15000 });
  if (title) {
    var ti = page.locator('textarea[placeholder="请在这里输入标题"]');
    await ti.fill(title);
    await page.waitForTimeout(300);
  }
  await page.evaluate((h) => {
    var pm = document.querySelector('.ProseMirror');
    pm.focus();
    var dt = new DataTransfer();
    dt.setData('text/html', h);
    var ev = new ClipboardEvent('paste', {bubbles:true, cancelable:true, clipboardData:dt});
    pm.dispatchEvent(ev);
  }, html);
  await page.waitForTimeout(1500);
  var enableBtns = page.locator('label:has-text("开启")');
  var cnt = await enableBtns.count();
  for (var i = 0; i < cnt; i++) {
    try {
      var b = enableBtns.nth(i);
      if (await b.isVisible({ timeout: 500 })) await b.click({ timeout: 1000 });
    } catch(e) {}
  }
  await page.waitForTimeout(500);
  var saveBtn = page.getByRole('button', { name: '保存为草稿' });
  await saveBtn.click();
  await page.waitForTimeout(2000);
  return title + ' -> saved';
}